Rule.Source:
//imported from iiq console
  import sailpoint.api.IdentityService;
  import sailpoint.object.Application;
  import sailpoint.tools.GeneralException;

  log.error("  AD Account Existed Identity Rule: ");

  boolean returnValue = false;
  Application adApp = null;

  try {
    IdentityService idService = new IdentityService(context);
    adApp = context.getObjectByName(Application.class, "ActiveDirectory");

    if (adApp != null && idService.countLinks(identity, adApp) > 0) {
      returnValue = true;
    }

  } catch (GeneralException e) {
    log.error("Error checking AD links : ", e);
  } finally {
    if (adApp != null) {
      context.decache(adApp);
    }
  }

  return returnValue;
